type Entity = "user" | "order" | "product";
type Action = "created" | "updated" | "deleted";

// Template literal type — all 9 combinations
type EventName = `${Entity}:${Action}`;

function on(event: EventName, handler: () => void): void {
  console.log(`Registered: ${event}`);
  handler();
}

on("user:created",   () => console.log("  → sending welcome email"));
on("order:updated",  () => console.log("  → notifying customer"));
on("product:deleted",() => console.log("  → clearing cache"));
