type OrderStatus = "draft" | "pending" | "processing" | "shipped" | "delivered" | "cancelled";

function getStatusColor(status: OrderStatus): string {
  const colors: Record<OrderStatus, string> = {
    draft:      "gray",
    pending:    "yellow",
    processing: "blue",
    shipped:    "indigo",
    delivered:  "green",
    cancelled:  "red",
  };
  return colors[status];
}

function canTransition(from: OrderStatus, to: OrderStatus): boolean {
  const allowed: Partial<Record<OrderStatus, OrderStatus[]>> = {
    draft:      ["pending", "cancelled"],
    pending:    ["processing", "cancelled"],
    processing: ["shipped"],
    shipped:    ["delivered"],
  };
  return (allowed[from] ?? []).includes(to);
}

const statuses: OrderStatus[] = ["draft", "pending", "shipped", "delivered"];
for (const s of statuses) {
  console.log(`${s}: ${getStatusColor(s)}`);
}
console.log(`draft → pending: ${canTransition("draft", "pending")}`);
console.log(`shipped → pending: ${canTransition("shipped", "pending")}`);

// Regular number loses precision above 2^53
const maxSafe = Number.MAX_SAFE_INTEGER;
console.log(`Max safe int: ${maxSafe}`);
console.log(`Max safe + 1: ${maxSafe + 1}`);
console.log(`Max safe + 2: ${maxSafe + 2}`);  // same as +1 — precision lost!

// BigInt keeps exact precision
const bigMax = BigInt(Number.MAX_SAFE_INTEGER);
console.log(`BigInt max: ${bigMax}`);
console.log(`BigInt + 1: ${bigMax + 1n}`);
console.log(`BigInt + 2: ${bigMax + 2n}`);  // correctly different

const ID   = Symbol("id");
const NAME = Symbol("name");

// Two symbols are never equal, even with the same description
const s1 = Symbol("test");
const s2 = Symbol("test");
console.log(`s1 === s2: ${String(s1 === s2)}`);  // always false

// Symbols as object keys — won't collide with string keys
const obj: { [k: symbol]: string; name?: string } = {};
obj[ID]   = "unique-id-42";
obj[NAME] = "Alice";

console.log(`ID:   ${String(obj[ID])}`);
console.log(`NAME: ${String(obj[NAME])}`);
console.log(`Symbol keys hidden from Object.keys: ${JSON.stringify(Object.keys(obj))}`);

// const → literal type (narrow)
const greeting = "hello";   // type: "hello"
