// Double assertion — when TypeScript refuses a direct assertion
// Use sparingly — it means you're bypassing two levels of safety
const config = { debug: true, version: 3 } as unknown as { env: string };
console.log(`Config type: ${typeof config}`);

interface Config {
  database: {
    host: string;
    port: number;
  } | null;
}

const config: Config = {
  database: {
    host: "localhost",
    port: 5432,
  }
};

// Without non-null assertion: TypeScript complains
// config.database.host;  // Error: Object is possibly null

// With non-null assertion: you're telling TypeScript "I guarantee it's not null"
const host = config.database!.host;
const port = config.database!.port;

console.log(`Database: ${host}:${port}`);

// Safer alternative: optional chaining
const safeHost = config.database?.host ?? "default";
console.log(`Safe host: ${safeHost}`);

function processValue(value: string | number | boolean | null): string {
  if (value === null) {
    return "[null]";
  }

  switch (typeof value) {
    case "string":
      return `string: "${value.toUpperCase()}"`;
    case "number":
      return `number: ${value.toFixed(2)}`;
    case "boolean":
      return `boolean: ${value ? "YES" : "NO"}`;
    default:
      return `unknown: ${String(value)}`;
  }
}

const values = ["hello", 42, 3.14159, true, false, null];
for (const v of values) {
  console.log(processValue(v));
}

interface SuccessResponse { status: "success"; data: unknown; }
interface ErrorResponse   { status: "error";   message: string; code: number; }

type ApiResponse = SuccessResponse | ErrorResponse;

function isSuccess(r: ApiResponse): r is SuccessResponse {
  return r.status === "success";
}

function isError(r: ApiResponse): r is ErrorResponse {
  return r.status === "error";
}

const responses: ApiResponse[] = [
  { status: "success", data: { users: 42 } },
  { status: "error",   message: "Not found",       code: 404 },
  { status: "success", data: { products: 100 } },
  { status: "error",   message: "Unauthorized",    code: 401 },
];

for (const r of responses) {
  if (isSuccess(r)) {
    console.log(`✓ Data: ${JSON.stringify(r.data)}`);
  } else {
    console.log(`✗ ${r.code}: ${r.message}`);
  }
}

type Method = "GET" | "POST" | "PUT" | "DELETE";
type Route = { method: Method; path: string; handler: string };

// 'satisfies' validates the array elements
// but preserves the exact literal types of each element
const routes = [
  { method: "GET",    path: "/users",    handler: "listUsers"  },
  { method: "POST",   path: "/users",    handler: "createUser" },
  { method: "GET",    path: "/users/:id",handler: "getUser"    },
  { method: "DELETE", path: "/users/:id",handler: "deleteUser" },
] satisfies Route[];

const getMethods = routes
  .filter(r => r.method === "GET")
  .map(r => `GET ${r.path}`);

console.log(`Total routes: ${routes.length}`);
console.log(`GET routes: ${getMethods.join(", ")}`);

